   186	        public ParallelQuery<KeyValuePair<CkanModule, HashSet<string>>> Supporters(
   187	            HashSet<CkanModule>     supported,
   188	            IEnumerable<CkanModule> toExclude)
   189	            => registry.CompatibleModules(options.stability_tolerance ?? new StabilityToleranceConfig(""),
   190	                                          versionCrit)
   191	                       .Except(toExclude)
   192	                       .AsParallel()
   193	                       // Find installable modules with "supports" relationships
   194	                       .Where(mod => !registry.IsInstalled(mod.identifier)
   195	                                     && mod.supports != null)
   196	                       // Find each module that "supports" something we're installing
   197	                       .Select(mod => new KeyValuePair<CkanModule, HashSet<string>>(
   198	                                          mod,
   199	                                          (mod.supports ?? Enumerable.Empty<RelationshipDescriptor>())
   200	                                             .Where(rel => rel.MatchesAny(supported, null, null))
   201	                                             .Select(rel => (rel as ModuleRelationshipDescriptor)?.name)
   202	                                             .OfType<string>()
   203	                                             .Where(name => !string.IsNullOrEmpty(name))
   204	                                             .ToHashSet()))
   205	                       .Where(kvp => kvp.Value.Count > 0);
