   207	        /// <summary>
   208	        /// Returns a dictionary consisting of KeyValuePairs containing conflicting mods.
   209	        /// The keys are the mods that the user chose that led to the conflict being in the list!
   210	        /// Use this for coloring/labelling rows, use ConflictDescriptions for reporting the conflicts to the user.
   211	        /// </summary>
   212	        public Dictionary<CkanModule, string> ConflictList
   213	            => conflicts
   214	                .SelectMany(kvp => UserReasonsFor(kvp.Key).Select(k => new KeyValuePair<CkanModule, ModPair>(k, kvp)))
   215	                .GroupBy(kvp => kvp.Key)
   216	                .ToDictionary(group => group.Key,
   217	                              group => string.Join(", ", group.Select(kvp => kvp.Value)
   218	                                                              .Distinct()
   219	                                                              .Select(origKvp => string.Format(
   220	                        Properties.Resources.RelationshipResolverConflictsWith,
   221	                        conflictingModDescription(origKvp.Key, null),
   222	                        conflictingModDescription(origKvp.Value, null)))));
