   232	                                      || totalDependers(kvp.Key) <= totalDependers(kvp.Value))
   233	                        .Select(kvp => string.Format(
   234	                            Properties.Resources.RelationshipResolverConflictsWith,
   235	                            conflictingModDescription(kvp.Key,   null),
   236	                            conflictingModDescription(kvp.Value, null)));
