   248	        /// <summary>
   249	        /// Indicates whether a module should be considered auto-installed in this change set.
   250	        /// A mod is auto-installed if it is in the list because it's a dependency
   251	        /// and if its depending mod is not a metpaackage.
   252	        /// </summary>
   253	        /// <param name="mod">Module to check</param>
   254	        /// <returns>
   255	        /// true if auto-installed, false otherwise
   256	        /// </returns>
   257	        public bool IsAutoInstalled(CkanModule mod)
