   152	                        RelationshipResolverOptions.ConflictsOpts(inst.StabilityToleranceConfig),
   153	                        registry, game, versionCrit);
   154	                    var conflicts = resolver.ConflictList;
   155	                    // Apparently ListView handes AddRange by:
   156	                    //   1. Expanding the Items list to the new size by filling it with nulls
   157	                    //   2. One by one, replace each null with a real item and call _ItemChecked
   158	                    // ... so the Items list can contain null!!
   159	                    foreach (var item in RecommendedModsListView.Items.OfType<ListViewItem>())
   160	                    {
   161	                        item.BackColor = item.Tag is CkanModule m && conflicts.ContainsKey(m)
   162	                            ? Color.LightCoral
   163	                            : Color.Empty;
   164	                    }
   165	                    RecommendedModsContinueButton.Enabled = conflicts.Count == 0;
   166	                    OnConflictFound?.Invoke(string.Join("; ", resolver.ConflictDescriptions));
