   221	        public override IEnumerable<ResolvedRelationship[]> UnsatisfiedFrom()
   222	        {
   223	            // Our goal here is to return an array of ResolvedRelationships for each full
   224	            // trace from rr to a relationship we can't satisfy.
   225	            // First we need to make sure we even care about this one, i.e. that it's required.
   226	            if (reason is SelectionReason.Depends)
   227	            {
   228	                // Now if this relationship itself can't be resolved directly, return it.
   229	                if (Unsatisfied())
   230	                {
   231	                    return Enumerable.Repeat(new ResolvedRelationship[] { this }, 1);
   232	                }
   233	                // Now we know it's a dependency that has at least one option for satisfying it,
   234	                // but those options may or may not be fully satisfied when considering _their_ dependencies.
   235	
   236	                // If any of these options works, then we want to return nothing.
   237	                // Otherwise we want to return all of the descriptions of why everything failed,
   238	                // with rr prepended to the start of each array.
   239	                var unsats = resolved.Values.Select(modsRels => modsRels.SelectMany(rr => rr.UnsatisfiedFrom())
   240	                                                                        .ToArray())
   241	                                            .Memoize();
   242	
   243	                return unsats.Any(u => u.Length == 0)
   244	                    // One of the dependencies is fully satisfied
   245	                    ? Enumerable.Empty<ResolvedRelationship[]>()
   246	                    : unsats.SelectMany(uns => uns.Select(u => u.Prepend(this).ToArray()));
   247	            }
   248	            return Enumerable.Empty<ResolvedRelationship[]>();
   249	        }
   250	
   251	        public override IReadOnlyCollection<(ResolvedRelationship[], Relationship)> BadRelationships(IReadOnlyCollection<CkanModule> installing)
   252	        {
   253	            if (reason is SelectionReason.Depends)
   254	            {
   255	                var unsatisfied = new List<(ResolvedRelationship[], Relationship)>();
   256	                foreach ((CkanModule module, ResolvedRelationship[] resRels) in resolved)
   257	                {
   258	                    if (module.BadRelationships(installing)
   259	                              .Select(r => (new ResolvedRelationship[] { this }, r))
   260	                              .ToArray()
   261	                        is { Length: > 0 } badRels)
   262	                    {
   263	                        unsatisfied.AddRange(badRels);
   264	                    }
   265	                    else if (resRels.SelectMany(rr => rr.BadRelationships(installing))
   266	                                    .Select(tuple => (tuple.Item1.Prepend(this).ToArray(),
   267	                                                      tuple.Item2))
   268	                                    .ToArray()
   269	                             is { Length: > 0 } badRRs)
   270	                    {
   271	                        unsatisfied.AddRange(badRRs);
   272	                    }
   273	                    else
   274	                    {
   275	                        // This relationship is satisfied
   276	                        return Array.Empty<(ResolvedRelationship[], Relationship)>();
   277	                    }
   278	                }
   279	                return unsatisfied;
   280	            }
   281	            return Array.Empty<(ResolvedRelationship[], Relationship)>();
