                ""spec_version"": 1,
                ""identifier"":   ""ReproModA"",
                ""name"":         ""Repro Mod A"",
                ""author"":       ""author"",
                ""version"":      ""1.0"",
                ""download"":     ""https://www.example.com/ReproModA.zip"",
                ""conflicts"":    [ { ""name"": ""ReproModB"" } ]
            }");
            var modB = CkanModule.FromJson(@"{
                ""spec_version"": 1,
                ""identifier"":   ""ReproModB"",
                ""name"":         ""Repro Mod B"",
                ""author"":       ""author"",
                ""version"":      ""1.0"",
                ""download"":     ""https://www.example.com/ReproModB.zip"",
                ""conflicts"":    [ { ""name"": ""ReproModA"" } ]
            }");
            var recommender = CkanModule.FromJson(@"{
                ""spec_version"": 1,
                ""identifier"":   ""ReproRecommender"",
                ""name"":         ""Repro Recommender"",
                ""author"":       ""author"",
                ""version"":      ""1.0"",
                ""download"":     ""https://www.example.com/ReproRecommender.zip"",
                ""recommends"":   [
                    { ""name"": ""ReproModA"" },
                    { ""name"": ""ReproModB"" }
                ]
            }");

            var user = new NullUser();
            using (var repo = new TemporaryRepository(modA.ToJson(), modB.ToJson(), recommender.ToJson()))
            using (var repoData = new TemporaryRepositoryData(user, repo.repo))
            {
                var registry = new CKAN.Registry(repoData.Manager, repo.repo);
                var list = new List<CkanModule> { recommender };

                // Use KitchenSinkOpts like the real installation code does
                var opts = RelationshipResolverOptions.KitchenSinkOpts(stabilityTolerance);
                var resolver = new RelationshipResolver(list, null, opts, registry, game, crit);

                var allMods = resolver.ModList().ToList();

                // Both ModA and ModB should be in the modlist
                Assert.That(allMods.Any(m => m.identifier == "ReproModA"),
                    "ReproModA should be in the modlist");
                Assert.That(allMods.Any(m => m.identifier == "ReproModB"),
                    "ReproModB should be in the modlist");

                // There should be conflicts detected
                Assert.That(resolver.ConflictList.Count > 0,
                    "Conflicts should be recorded");
            }
        }

        public static string MergeWithDefaults(string json)
        {
            var incoming = JObject.Parse(json);
            incoming.SafeMerge(moduleDefaults);
            return incoming.ToString();
        }

        public static IEnumerable<string> MergeWithDefaults(params string[] jsons)
            => jsons.Select(MergeWithDefaults);

        // Unimportant required fields that we don't want to duplicate
        private static readonly JObject moduleDefaults = JObject.Parse(
            @"{
                ""spec_version"": ""v1.34"",
